VALUES
  ('judicial-57112235-moex-00097', 'judicial-57112235', 'judicial-57112235-moex-114-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '根據學者VanNess所述在監獄推動修復式正義之教化課程設計，應包含五種不同內容之課程。請 問下列何種課程旨在「幫助受刑人了解犯罪事件對被害人之衝擊與影響，進而導正受刑人之錯誤 觀念」？', '["道歉賠償課程", "監獄與社區關係課程", "排除衝突課程", "被害感知與同理心課程"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:49+00:00", "source_pdf_sha1": "83a7e2e69390", "answer_pdf_sha1": "9529cae49e00", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "205", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00098', 'judicial-57112235', 'judicial-57112235-moex-114-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '有關監獄的主管與監督機關，以及監獄和視察、訪視人員之關係，下列敘述何者錯誤？', '["主管機關為法務部", "監督機關為法務部矯正署", "視察人員為主管機關人員，每季至少一次", "訪視人員係指少年法院法官與地檢署檢察官，得就執行刑罰事項，隨時訪視少年矯正學校、監獄"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:49+00:00", "source_pdf_sha1": "eb79723e3a75", "answer_pdf_sha1": "e4b9650e68ac", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00099', 'judicial-57112235', 'judicial-57112235-moex-114-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '有關監獄執行之對象，下列敘述何者錯誤？', '["徒刑之受刑人", "拘役之受刑人", "罰金易服勞役之受刑人", "罰金易服社會勞動之受刑人"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:49+00:00", "source_pdf_sha1": "eb79723e3a75", "answer_pdf_sha1": "e4b9650e68ac", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00100', 'judicial-57112235', 'judicial-57112235-moex-114-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '依監獄行刑法之規定，制定本法的目的為下列何者？', '["應報", "隔離", "矯治", "威嚇"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:49+00:00", "source_pdf_sha1": "eb79723e3a75", "answer_pdf_sha1": "e4b9650e68ac", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00101', 'judicial-57112235', 'judicial-57112235-moex-114-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '依監獄行刑法之規定，有關少年受刑人之收容，下列敘述何者正確？', '["未滿十八歲之少年受刑人，應收容於少年監獄，並按其性別分別收容", "收容中滿十八歲而殘餘刑期未滿三個月者，得繼續收容於少年矯正學校", "滿十八歲之少年受刑人，得依其教育需要，收容於少年矯正學校至滿二十二歲為止", "受刑人滿二十二歲而未完成該級教育階段者，得由少年矯正學校報請主管機關同意，收容至完成該 級教育階段為止"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:49+00:00", "source_pdf_sha1": "eb79723e3a75", "answer_pdf_sha1": "e4b9650e68ac", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00102', 'judicial-57112235', 'judicial-57112235-moex-114-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '對於新入監者，應就其個性、身心狀況及其他相關事項，加以調查，有關調查期間規定，下列敘述何者正 確？', '["不得逾二個月", "不得逾三個月", "不得逾四個月", "不得逾六個月"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:49+00:00", "source_pdf_sha1": "eb79723e3a75", "answer_pdf_sha1": "e4b9650e68ac", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00103', 'judicial-57112235', 'judicial-57112235-moex-114-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '有關監獄行刑法第28條及相關受刑人返家探視規定，下列敘述何者正確？', '["受刑人之祖父母、父母、配偶、子女喪亡時，應經監獄長官核准戒護返家探視", "受刑人須於二十四小時內回監；其在外期間，予以計算刑期", "收容人之祖父母、配偶、子女，如有生命危險，得經監獄長官核准戒護返家探視", "本條返家探視之申請，同一事由以二次為限"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:49+00:00", "source_pdf_sha1": "eb79723e3a75", "answer_pdf_sha1": "e4b9650e68ac", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00104', 'judicial-57112235', 'judicial-57112235-moex-114-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '監獄行刑法為落實「透明化原則」，訂定許多條文以保障受刑人權益，但不包含下列那一規定？', '["第2條第4項：少年法院法官、檢察官執行刑罰有關事項，得隨時訪視少年矯正學校、監獄", "第7條第1項：監獄應設獨立之外部視察小組，置委員三人至七人，任期二年，均為無給職，由監 督機關陳報法務部核定後遴聘之", "第8條：監獄得依媒體之請求，同意其進入適當處所採訪或參觀；並得依民眾之請求，同意其進入 適當處所參觀", "第30條：監獄得遴選具有特殊才藝或技能之受刑人，於徵得其同意後，報請監督機關核准，戒護 外出參加公益活動、藝文展演、技職檢定、才藝競賽或其他有助教化之活動"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:49+00:00", "source_pdf_sha1": "eb79723e3a75", "answer_pdf_sha1": "e4b9650e68ac", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00105', 'judicial-57112235', 'judicial-57112235-moex-114-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '受刑人新入監考核後，除另有規定外，應予以編為四級，施予累進處遇。但其富有責任觀念，且有適 於共同生活之情狀時，依行刑累進處遇條例第14條，經監獄委員會決議後，得不受前述編入四級之 規定，使進列適當之階段，稱為：', '["逕編一級", "逕編二級", "逕編三級", "逕編原級"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:49+00:00", "source_pdf_sha1": "eb79723e3a75", "answer_pdf_sha1": "e4b9650e68ac", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00106', 'judicial-57112235', 'judicial-57112235-moex-114-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '依監獄行刑法之入監規定，下列敘述何者錯誤？', '["受刑人入監時，應行健康檢查，受刑人不得拒絕", "監獄應於受刑人入監後三個月內，依相關事項之調查資料，訂定其個別處遇計畫，並適時修正", "殘餘刑期在二個月以下之入監或在監婦女請求攜帶未滿三歲之子女，監獄得准許之", "受刑人懷胎二月以上，或生產未滿五月，應拒絕收監"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:49+00:00", "source_pdf_sha1": "eb79723e3a75", "answer_pdf_sha1": "e4b9650e68ac", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL)
